5	#include "radix_tree.h"
6	
7	#include <tvm/ffi/function.h>
8	#include <tvm/ffi/reflection/registry.h>
9	#include <tvm/runtime/logging.h>
10	
11	namespace mlc {
12	namespace llm {
13	namespace serve {
14	
15	using namespace tvm::runtime;
16	
17	TVM_FFI_STATIC_INIT_BLOCK() { PagedRadixTreeObj::RegisterReflection(); }
18	
19	/*!
20	 * \brief The sequence ID linked list structure in paged radix tree node.
21	 */
22	struct SequenceIDNode {
23	  /*! \brief The stored sequence ID. */
24	  int64_t id = 0;
25	  /*! \brief The pointer to the next sequence ID. */
26	  SequenceIDNode* next = nullptr;
27	};
28	
29	/*!
30	 * \brief The sequence ID node pool.
31	 *
32	 * The sequence ID node pool allocates a block of sequence ID nodes when pool is full,
33	 * and frees all when destruction, to avoid frequent memory operation.
34	 */
35	class SequenceIDNodePool {
36	 public:
37	  /*! \brief The constructor of sequence ID node pool, allocating a new sequence ID node block. */
38	  SequenceIDNodePool() {
39	    NewNodeBlock_();
40	    used_nodes_.clear();
41	  }
42	
43	  /*!
44	   * \brief Get a sequence ID node from pool, and assign the fields.
45	   * If there is no available node, it will allocate a new sequence ID node block.
46	   * \param seq_id The assigned sequence ID of allocated sequence ID node.
47	   * \param node The next sequence ID node pointer of allocated sequence ID node.
48	   * \return The allocated radix page.
49	   */
50	  SequenceIDNode* Allocate(int64_t seq_id, SequenceIDNode* next) {
51	    if (free_node_indices_.empty()) {
52	      NewNodeBlock_();
53	      TVM_FFI_ICHECK(!free_node_indices_.empty());
54	    }
55	    size_t id = free_node_indices_.back();
56	    free_node_indices_.pop_back();
57	    SequenceIDNode* node = nodes_[id];
58	    used_nodes_[node] = id;
59	    node->id = seq_id;
60	    node->next = next;
61	    return node;
62	  }
63	
64	  /*!
65	   * \brief Free a sequence ID node to pool.
66	   * \param node The sequence ID node to free.
67	   */
68	  void Free(SequenceIDNode* node) {
69	    TVM_FFI_ICHECK(used_nodes_.find(node) != used_nodes_.end());
70	    free_node_indices_.push_back(used_nodes_[node]);
71	    used_nodes_.erase(node);
72	  }
73	
74	  /*!
75	   * \brief Reset the sequence ID node pool to initial status.
76	   */
77	  void Reset() {
78	    used_nodes_.clear();
79	    free_node_indices_.reserve(nodes_.size());
80	    for (size_t i = 0; i < nodes_.size(); ++i) {
81	      nodes_[i]->id = 0;
82	      nodes_[i]->next = nullptr;
83	      free_node_indices_[i] = i;
84	    }
85	  }
86	
87	  /*! \brief The destructor of sequence ID node pool, freeing memory for each node. */
88	  ~SequenceIDNodePool() {
89	    for (SequenceIDNode* node_block : node_blocks_) {
90	      delete[] node_block;
91	    }
92	  }
93	
94	 private:
95	  /*! \brief The size of each node pool block. */
96	  static constexpr size_t kNodeBlockSize_ = 64;
97	  /*! \brief The raw sequence ID node block pool, each element is a sequence ID node array. */
98	  std::vector<SequenceIDNode*> node_blocks_;
99	  /*! \brief The sequence ID node pool, each element is a sequence ID node pointer. */
100	  std::vector<SequenceIDNode*> nodes_;
101	  /*! \brief The indices of free sequence ID node in node pool. */
102	  std::vector<size_t> free_node_indices_;
103	  /*! \brief The map from used paged sequence ID node to its index in node pool. */
104	  std::unordered_map<SequenceIDNode*, size_t> used_nodes_;
105	
106	  /*! \brief Allocate a new node pool block. */
107	  void NewNodeBlock_() {
108	    size_t node_id_offset = node_blocks_.size() * kNodeBlockSize_;
109	    node_blocks_.push_back(new SequenceIDNode[kNodeBlockSize_]);
110	    nodes_.reserve(nodes_.size() + kNodeBlockSize_);
111	    free_node_indices_.reserve(free_node_indices_.size() + kNodeBlockSize_);
112	    for (size_t i = 0; i < kNodeBlockSize_; ++i) {
113	      nodes_.push_back(&node_blocks_.back()[i]);
114	      free_node_indices_.push_back(i + node_id_offset);
115	    }
116	  }
117	};
118	
119	/*!
120	 * \brief The paged radix tree node data structure.
121	 *
122	 * The paged radix tree node is similar to original radix tree node, but with the limited length for
123	 * prefix in page, so that the memory usage in each page is the same and is fixed once allocated.
124	 * Since the page only consists of pointers and int tokens, the page memory layout is int array
125	 * indeed. The lower offset is the pointers and page information, while the higher offset is the
126	 * stored prefix tokens.
127	 *
128	 * And since the vocabulary size may be very large, the paged Radix tree is represented
129	 * as left-child, right-sibling binary tree.
130	 *
131	 * Also, due to possible pop/push front/back tokens in page, the page is designed as circular
132	 * buffer, to make full use of each page.
133	 *
134	 * Each page records the sequence exactly ends with the prefix tokens stored in page. In other word,
135	 * all sequences locate in the boundary of each page, or the end of each page.
136	 */
137	struct RadixPage {
138	  /*! \brief The parent page. */
139	  RadixPage* parent;
140	  /*! \brief The first child page. */
141	  RadixPage* first_child;
142	  /*! \brief The sibling page sharing the same parent page. */
143	  RadixPage* next_sibling;
144	  /*! \brief The head of sequence ID linked list. */
145	  SequenceIDNode* seq_ids;
146	  /*! \brief The capacity of maximum stored prefix tokens. */
147	  size_t capacity;
148	  /*! \brief The start offset of stored prefix tokens. The legal value is of [0, capacity). */
149	  size_t offset;
150	  /*! \brief The length of stored prefix tokens. The legal value is of [0, capacity). */
151	  size_t length;
152	  /*! \brief The offset of first prefix token in memory layout. */
153	  static constexpr int kDataOffset = (sizeof(RadixPage*) * 3 + sizeof(SequenceIDNode*) +
154	                                      sizeof(size_t) * 3 + sizeof(int32_t) - 1) /
155	                                     sizeof(int32_t);
156	
157	  /*!
158	   * \brief Overload operator [] to get the prefix tokens by index as simple int array.
159	   * \param i The prefix token index.
160	   * \return The value of i-th prefix token.
161	   */
162	  int32_t& operator[](size_t i) {
163	    return reinterpret_cast<int32_t*>(this)[kDataOffset + (i + offset) % capacity];
164	  }
165	
166	  /*!
167	   * \brief Extend or push back a suffix tokens in page.
168	   * \param suffix The suffix tokens array.
169	   * \param suffix_length The suffix length to extend.
170	   * \throw Error if suffix length is larger than current vacant space.
171	   */
172	  void Extend(const int32_t* suffix, size_t suffix_length) {
173	    TVM_FFI_ICHECK_LE(suffix_length + length, capacity);
174	    for (int i = 0; i < suffix_length; ++i) {
175	      (*this)[i + length] = suffix[i];
176	    }
177	    length += suffix_length;
178	  }
179	
180	  /*!
181	   * \brief Add a sequence ID in page.
182	   * \param pool The sequence ID node pool to allocate new node.
183	   * \param id The sequence ID to add.
184	   */
185	  void AddSequence(SequenceIDNodePool* pool, int64_t id) { seq_ids = pool->Allocate(id, seq_ids); }
186	
187	  /*!
188	   * \brief Pop a sequence ID in page.
189	   * \param pool The sequence ID node pool to free popped node.
190	   * \param id The sequence ID to pop.
191	   * \throw Error if no such sequence ID in page.
192	   */
193	  void PopSequence(SequenceIDNodePool* pool, int64_t id) {
194	    if (seq_ids->id == id) {
195	      // If the popped sequence ID is the first node in linked list,
196	      // directly skip from head and free it.
197	      SequenceIDNode* next = seq_ids->next;
198	      pool->Free(seq_ids);
199	      seq_ids = next;
200	    } else {
201	      // If the popped sequence ID is not the first node in linked list,
202	      // skip it from previous node and free it.
203	      SequenceIDNode* last = seq_ids;
204	      SequenceIDNode* cur = seq_ids->next;
205	      while (cur) {
206	        if (cur->id == id) {
207	          last->next = cur->next;
208	          pool->Free(cur);
209	          return;
210	        }
211	        last = cur;
212	        cur = cur->next;
213	      }
214	      LOG(FATAL) << "Sequence ID = " << id << " not found.";
215	    }
216	  }
217	
218	  /*!
219	   * \brief Get all sequence ID in page.
220	   * \return The std::vector of sequence ID in page.
221	   */
222	  std::vector<int64_t> GetLocalSequence() {
223	    std::vector<int64_t> output;
224	    for (SequenceIDNode* node = seq_ids; node; node = node->next) {
225	      output.push_back(node->id);
226	    }
227	    return output;
228	  }
229	
230	  /*!
231	   * \brief Get any sequence ID in current page or child pages.
232	   * Since there is always a sequence in leaf pages, it only check first child if no sequence ID in
233	   * current page.
234	   * \return The any sequence ID in current page or child pages.
235	   */
236	  int32_t FindAnyChildSequence() {
237	    if (seq_ids) return seq_ids->id;
238	    return first_child->FindAnyChildSequence();
239	  }
240	
241	  /*!
242	   * \brief Get all sequence ID in current page and child pages, using Iterate method with lambda
243	   * expression as callback to avoid frequently memory allocation of std::vector.
244	   * \return The std::vector of all sequence ID in current page and child pages.
245	   */
246	  std::vector<int64_t> FindAllChildSequence() {
247	    std::vector<int64_t> output = GetLocalSequence();
248	    if (first_child) {
249	      first_child->Iterate([&output](const RadixPage* page) {
250	        for (SequenceIDNode* node = page->seq_ids; node; node = node->next) {
251	          output.push_back(node->id);
252	        }
253	      });
254	    }
255	    return output;
256	  }
257	
258	  /*!
259	   * \brief The iteration method for tree or sub-tree traverse.
260	   * \param f The callback function to invoke at each radix page visited.
261	   */
262	  template <class CallbackFunc>
263	  void Iterate(CallbackFunc f) {
264	    f(this);
265	    if (next_sibling) next_sibling->Iterate(f);
266	    if (first_child) first_child->Iterate(f);
267	  }
268	
269	  /*!
270	   * \brief Get the last sibling of current page.
271	   * \return The page whose next_sibling is current page, or nullptr if current is the first_child
272	   * of its parent page.
273	   */
274	  RadixPage* GetLastSibling() {
275	    if (parent == nullptr) return nullptr;
276	    if (parent->first_child == this) return nullptr;
277	    for (RadixPage* child = parent->first_child; child; child = child->next_sibling) {
278	      if (child->next_sibling == this) return child;
279	    }
280	    return nullptr;
281	  }
282	
283	  /*!
284	   * \brief Find the child indexed by first token.
285	   * \return The child page started with first token, or nullptr if no such child page.
286	   */
287	  RadixPage* FindChild(int64_t first_token) {
288	    int32_t casted = first_token;
289	    // Iterate all child radix pages, as the child radix pages are stored unorderly.
290	    for (RadixPage* child = first_child; child; child = child->next_sibling) {
291	      if ((*child)[0] == casted) return child;
292	    }
293	    return nullptr;
294	  }
295	
296	  /*! \brief Insert a new child page. */
297	  void InsertChild(RadixPage* child) {
298	    child->parent = this;
299	    child->next_sibling = first_child;
300	    first_child = child;
301	  }
302	
303	  /*!
304	   * \brief Remove a child page.
305	   * \throw Error if page to be removed is not child page.
306	   */
307	  void RemoveChild(RadixPage* child) {
308	    TVM_FFI_ICHECK(child->parent == this);
309	    if (first_child == child) {
310	      first_child = child->next_sibling;
311	    } else {
312	      child->GetLastSibling()->next_sibling = child->next_sibling;
313	    }
314	  }
315	
316	  /*!
317	   * \brief Check current page is mergable with its child page.
318	   * The page is mergable if and only if
319	   * 1. No sequence ID in current page, as sequence ID is not allowed to exist within page.
320	   * 2. The current page has child page.
321	   * 3. The current page has only one child page.
322	   * 4. The current page prefix and the child page prefix can be concatenated into one page.
323	   * \return True if current page is mergable, or false.
324	   */
325	  bool Mergeable() {
326	    if (seq_ids) return false;
327	    if (!first_child) return false;
328	    if (first_child->next_sibling) return false;
329	    if (length + first_child->length > capacity) return false;
330	    return true;
331	  }
332	
333	  /*!
334	   * \brief Match the given prefix within page.
335	   * \param prefix The prefix token array.
336	   * \param prefix_length The length of prefix token array.
337	   * \return The matched prefix offset within page, or the first mismatched token position. The
338	   * possible return value is [0, page->length], where page->length means the page is completely the
339	   * prefix of given prefix.
340	   */
341	  size_t MatchPrefix(const int32_t* prefix, size_t prefix_length) {
342	    size_t n = std::min(length, prefix_length);
343	    for (int i = 0; i < n; ++i) {
344	      if ((*this)[i] != prefix[i]) return i;
345	    }
346	    return n;
347	  }
348	};
349	
350	/*!
351	 * \brief The paged radix tree page pool.
352	 *
353	 * The paged radix tree page pool allocates a block of radix tree pages when pool is full,
354	 * and frees all when destruction, to avoid frequent memory operation.
355	 */
356	class RadixPagePool {
357	 public:
358	  /*! \brief The constructor of paged radix tree page pool, allocating memory for each page. */
359	  RadixPagePool() {
360	    NewPageBlock_();
361	    used_pages_.clear();
362	  }
363	
364	  /*!
365	   * \brief Get a radix page from pool.
366	   * If there is no available page, it will allocate a new radix page block.
367	   * \return The allocated radix page.
368	   */
369	  RadixPage* Allocate() {
370	    if (free_page_indices_.empty()) {
371	      NewPageBlock_();
372	      TVM_FFI_ICHECK(!free_page_indices_.empty());
373	    }
374	    int id = free_page_indices_.back();
375	    free_page_indices_.pop_back();
376	    RadixPage* page = pages_[id];
377	    used_pages_[page] = id;
378	    page->parent = page->first_child = page->next_sibling = nullptr;
379	    page->capacity = kPageCapacity_;
380	    page->offset = page->length = 0;
381	    page->seq_ids = nullptr;
382	    return page;
383	  }
384	
385	  /*!
386	   * \brief Free a radix page to pool.
387	   * \param page The radix page to free.
388	   */
389	  void Free(RadixPage* page) {
390	    TVM_FFI_ICHECK_EQ(page->seq_ids, nullptr);
391	    TVM_FFI_ICHECK(used_pages_.find(page) != used_pages_.end());
392	    free_page_indices_.push_back(used_pages_[page]);
393	    TVM_FFI_ICHECK(used_pages_.erase(page));
394	  }
395	
396	  /*!
397	   * \brief Get the token capacity of free pages.
398	   * \return The the token capacity of free pages.
399	   */
400	  size_t FreeCapacity() { return free_page_indices_.size() * kPageCapacity_; }
401	
402	  /*!
403	   * \brief Reset the paged radix tree page pool to initial status.
404	   */
405	  void Reset() {
406	    used_pages_.clear();
407	    free_page_indices_.reserve(pages_.size());
408	    for (int i = 0; i < pages_.size(); ++i) {
409	      pages_[i]->parent = pages_[i]->first_child = pages_[i]->next_sibling = nullptr;
410	      pages_[i]->capacity = kPageCapacity_;
411	      pages_[i]->offset = pages_[i]->length = 0;
412	      pages_[i]->seq_ids = nullptr;
413	      free_page_indices_[i] = i;
414	    }
415	  }
416	
417	  /*! \brief The destructor of paged radix tree page pool, freeing memory for each page. */
418	  ~RadixPagePool() {
419	    for (int32_t* page_block : page_blocks_) {
420	      delete[] page_block;
421	    }
422	  }
423	
424	 private:
425	  /*! \brief The size of each page pool block. */
426	  static constexpr size_t kPageBlockSize_ = 64;
427	  /*! \brief The page capacity of each paged radix tree page. */
428	  static constexpr size_t kPageCapacity_ = 64;
429	  /*! \brief The page size of each paged radix tree page. */
430	  static constexpr size_t kPageSize_ = kPageCapacity_ + RadixPage::kDataOffset;
431	  /*! \brief The raw paged radix tree page block pool,
432	  each element is a raw paged radix tree page array. */
433	  std::vector<int32_t*> page_blocks_;
434	  /*! \brief The paged radix tree page pool,
435	  each element is a raw paged radix tree page pointer. */
436	  std::vector<RadixPage*> pages_;
437	  /*! \brief The indices of free paged radix page in page pool. */
438	  std::vector<size_t> free_page_indices_;
439	  /*! \brief The map from used paged radix tree page to its index in page pool. */
440	  std::unordered_map<RadixPage*, size_t> used_pages_;
441	
442	  /*! \brief Allocate a new page pool block. */
443	  void NewPageBlock_() {
444	    size_t page_id_offset = page_blocks_.size() * kPageBlockSize_;
445	    page_blocks_.push_back(new int32_t[kPageBlockSize_ * kPageSize_]);
446	    pages_.reserve(pages_.size() + kPageBlockSize_);
447	    free_page_indices_.reserve(free_page_indices_.size() + kPageBlockSize_);
448	    for (size_t i = 0; i < kPageBlockSize_; ++i) {
449	      pages_.push_back(reinterpret_cast<RadixPage*>(page_blocks_.back() + i * kPageSize_));
450	      free_page_indices_.push_back(i + page_id_offset);
451	    }
452	  }
453	};
454	
455	// PagedRadixTree
456	
457	/*!
458	 * \brief The paged radix tree data structure.
459	 */
460	class PagedRadixTreeImpl : public PagedRadixTreeObj {
461	 public:
462	  /*! \brief The map from sequence to paged radix tree node it is stored. */
463	  std::unordered_map<int32_t, RadixPage*> seq2page;
464	  /*! \brief The sequence ID node pool. */
465	  SequenceIDNodePool* seq_id_node_pool = nullptr;
466	  /*! \brief The radix page pool. */
467	  RadixPagePool* radix_page_pool = nullptr;
468	  /*! \brief The root page of paged radix tree. */
469	  RadixPage* root = nullptr;
470	
471	  explicit PagedRadixTreeImpl() {
472	    seq_id_node_pool = new SequenceIDNodePool();
473	    radix_page_pool = new RadixPagePool();
474	
475	    root = reinterpret_cast<RadixPage*>(new int32_t[RadixPage::kDataOffset]);
476	    root->parent = root->first_child = root->next_sibling = nullptr;
477	    root->offset = root->length = root->capacity = 0;
478	    root->seq_ids = nullptr;
479	  }
480	
481	  /*!
482	   * \brief Check if a sequence exists.
483	   * \param seq_id The sequence ID for index.
484	   * \return The sequence existence.
485	   * \throw Error if sequence ID is not valid.
486	   */
487	  bool HasSequence(int64_t seq_id) { return seq2page.find(seq_id) != seq2page.end(); }
488	
489	  /*!
490	   * \brief Get a sequence's all tokens.
491	   * \param seq_id The sequence ID for index.
492	   * \return The sequence tokens.
493	   * \throw Error if sequence ID is not valid.
494	   */
495	  Shape GetSequence(int64_t seq_id) {
496	    TVM_FFI_ICHECK(seq2page.find(seq_id) != seq2page.end());
497	    size_t length = GetSequenceLength(seq_id);
498	    std::vector<int64_t> output(length);
499	    size_t offset = length;
500	    for (RadixPage* page = seq2page[seq_id]; page; page = page->parent) {
501	      offset -= page->length;
502	      for (int i = 0; i < page->length; ++i) {
503	        output[offset + i] = (*page)[i];
504	      }
505	    }
506	    return Shape(output);
507	  }
508	
509	  /*!
510	   * \brief Get all sequences with longest common prefix with give prefix tokens.
511	   * \param tokens The prefix tokens for reference.
512	   * \return The pair of matched prefix length and the array of matched sequences indices.
513	   */
514	  std::pair<size_t, std::vector<int64_t>> MatchPrefix(const std::vector<int32_t>& tokens) {
515	    const int32_t* prefix = tokens.data();
516	    size_t length = tokens.size();
517	    auto [page, offset, in_page_offset] = MatchSequence(root, prefix, length);
518	    if (!offset) return std::make_pair(0, std::vector<int64_t>());
519	    return std::make_pair(offset, page->FindAllChildSequence());
520	  }
521	
522	  /*!
523	   * \brief Get a sequence's length.
524	   * \param seq_id The sequence ID for index.
525	   * \return The sequence length.
526	   * \throw Error if sequence ID is not valid.
527	   */
528	  size_t GetSequenceLength(int64_t seq_id) {
529	    TVM_FFI_ICHECK(seq2page.find(seq_id) != seq2page.end());
530	    size_t length = 0;
531	    for (RadixPage* page = seq2page[seq_id]; page; page = page->parent) {
532	      length += page->length;
533	    }
534	    return length;
535	  }
536	
537	  /*!
538	   * \brief Fork a sequence from parent sequence at given position.
539	   * \param seq_id The new sequence ID.
540	   * \param parent_seq_id The parent sequence ID to fork from.
541	   * \param forked_offset The position of parent sequence to fork at.
542	   * The valid value is [1, length of forked sequence]. If the position equals the length of forked
543	   * sequence, the new sequence will copy the entire forked sequence.
544	   * \throw Error if sequence ID or
545	   * forked postion is not valid.
546	   */
547	  void ForkSequence(int64_t seq_id, int64_t parent_seq_id, size_t forked_offset) {
548	    TVM_FFI_ICHECK(seq2page.find(seq_id) == seq2page.end());
549	    TVM_FFI_ICHECK(seq2page.find(parent_seq_id) != seq2page.end());
550	    TVM_FFI_ICHECK_GT(forked_offset, 0);
551	    size_t length = GetSequenceLength(parent_seq_id);
552	    TVM_FFI_ICHECK_LE(forked_offset, length);
553	    for (RadixPage* page = seq2page[parent_seq_id]; page; page = page->parent) {
554	      if (forked_offset > length - page->length) {
555	        if (forked_offset < length) {
556	          // Split radix page if forked position is within page
557	          page = SplitPage(page, forked_offset + page->length - length);
558	        }
559	        page->AddSequence(seq_id_node_pool, seq_id);
560	        seq2page[seq_id] = page;
561	        return;
562	      }
563	      length -= page->length;
564	    }
565	  }
566	
567	  /*!
568	   * \brief Add an empty sequence at root.
569	   * \param seq_id The new sequence ID.
570	   * \throw Error if sequence ID is not valid.
571	   */
572	  void AddSequence(int64_t seq_id) {
573	    TVM_FFI_ICHECK(seq2page.find(seq_id) == seq2page.end())
574	        << "Sequence ID = " << seq_id << " has been added.";
575	    root->AddSequence(seq_id_node_pool, seq_id);
576	    seq2page[seq_id] = root;
577	  }
578	
579	  /*!
580	   * \brief Extend a sequence with given tokens.
581	   * \param seq_id The sequence ID for index.
582	   * \param tokens The given tokens to extend.
583	   * \throw Error if sequence ID is not valid.
584	   */
585	  void ExtendSequence(int64_t seq_id, const std::vector<int32_t>& tokens) {
586	    TVM_FFI_ICHECK(seq2page.find(seq_id) != seq2page.end());
587	    const int32_t* suffix = tokens.data();
588	    size_t length = tokens.size();
589	    RadixPage* original_page = seq2page[seq_id];
590	    original_page->PopSequence(seq_id_node_pool, seq_id);
591	    auto [page, offset, in_page_offset] = MatchSequence(original_page, suffix, length);
592	    if (in_page_offset < page->length) {
593	      // Split page if extended sequence mismatches within page
594	      page = SplitPage(page, in_page_offset);
595	    }
596	    if (offset < length && !page->seq_ids && !page->first_child && page->capacity > page->length) {
597	      // Extend in the existing leaf page first if possible.
598	      size_t suffix_length = std::min(page->capacity - page->length, length - offset);
599	      page->Extend(suffix + offset, suffix_length);
600	      offset += suffix_length;
601	    }
602	    while (offset < length) {
603	      // Allocate new radix page and extend tokens
604	      RadixPage* new_page = radix_page_pool->Allocate();
605	      page->InsertChild(new_page);
606	      page = new_page;
607	      size_t suffix_length = std::min(page->capacity - page->length, length - offset);
608	      page->Extend(suffix + offset, suffix_length);
609	      offset += suffix_length;
610	    }
611	    page->AddSequence(seq_id_node_pool, seq_id);
612	    seq2page[seq_id] = page;
613	    if (original_page->Mergeable()) {
614	      // The original page may be mergeable, as the sequence ID changes
615	      MergePage(original_page);
616	    }
617	  }
618	
619	  /*!
620	   * \brief Roll back a sequence by number of tokens.
621	   * \param seq_id The sequence ID for index.
622	   * \param num_tokens The number of tokens to be rolled back.
623	   * \throw Error if sequence ID is not valid.
624	   */
625	  void RollBackSequence(int64_t seq_id, size_t num_tokens) {
626	    size_t length = GetSequenceLength(seq_id);
627	    TVM_FFI_ICHECK_GT(num_tokens, 0);
628	    TVM_FFI_ICHECK_LE(num_tokens, length);
629	    if (num_tokens == length) {
630	      // If rolling back whole sequence, just remove the sequence and add it again equivalently.
631	      RemoveSequence(seq_id);
632	      AddSequence(seq_id);
633	      return;
634	    }
635	    RadixPage* page = seq2page[seq_id];
636	    // Remove the sequence temporarily, but keeping the data and starting rolling back.
637	    page->PopSequence(seq_id_node_pool, seq_id);
638	    seq2page.erase(seq_id);
639	    while (page->length <= num_tokens) {
640	      // Roll back entire page
641	      num_tokens -= page->length;
642	      RadixPage* parent = page->parent;
643	      if (page->seq_ids == nullptr && page->first_child == nullptr) {
644	        // The leaf page is removable
645	        parent->RemoveChild(page);
646	        radix_page_pool->Free(page);
647	      }
648	      page = parent;
649	    }
650	    if (page->seq_ids == nullptr && page->first_child == nullptr) {
651	      // The page is leaf page, directly roll back in page length
652	      page->length -= num_tokens;
653	      // Update the mapping from sequence to page
654	      page->AddSequence(seq_id_node_pool, seq_id);
655	      seq2page[seq_id] = page;
656	      return;
657	    }
658	    // Split page for rolled back sequence
659	    if (num_tokens) {
660	      page = SplitPage(page, page->length - num_tokens);
661	    }
662	    // Update the mapping from sequence to page
663	    page->AddSequence(seq_id_node_pool, seq_id);
664	    seq2page[seq_id] = page;
665	  }
666	
667	  /*!
668	   * \brief Remove a sequence.
669	   * \param seq_id The sequence ID to remove.
670	   * \throw Error if sequence ID is not valid.
671	   */
672	  void RemoveSequence(int64_t seq_id) {
673	    RadixPage* page = seq2page[seq_id];
674	    page->PopSequence(seq_id_node_pool, seq_id);
675	    seq2page.erase(seq_id);
676	    while (page->parent && !page->seq_ids && !page->first_child) {
677	      RadixPage* parent = page->parent;
678	      parent->RemoveChild(page);
679	      radix_page_pool->Free(page);
680	      page = parent;
681	    }
682	    if (page && page->Mergeable()) {
683	      // The remaining page may be mergeable, as the sequence ID changes
684	      MergePage(page);
685	    }
686	  }
687	
688	  /*!
689	   * \brief Get the remaining token capacity of the paged radix tree.
690	   * \return The the remaining token capacity of the paged radix tree.
691	   */
692	  size_t FreeCapacity() { return radix_page_pool->FreeCapacity(); }
693	
694	  void Reset() {
695	    radix_page_pool->Reset();
696	    seq_id_node_pool->Reset();
697	    seq2page.clear();
698	    root->parent = root->first_child = root->next_sibling = nullptr;
699	    root->offset = root->length = root->capacity = 0;
700	    root->seq_ids = nullptr;
701	  }
702	
703	  /*! \brief The destructor to free root page. */
704	  ~PagedRadixTreeImpl() {
705	    delete[] reinterpret_cast<int32_t*>(root);
706	    delete seq_id_node_pool;
707	    delete radix_page_pool;
708	  }
709	
710	 private:
711	  /*!
712	   * \brief Merge a radix tree page with its child radix tree page, to save radix tree page.
713	   * e.g. MergePage([1, 2, _, _, _] -> [3, 4, 5, _, _]) = [1, 2, 3, 4, 5].
714	   * And the page to be merged should be page->Mergeable().
715	   * \param page The parent radix tree page.
716	   */
717	  void MergePage(RadixPage* page) {
718	    TVM_FFI_ICHECK(page->Mergeable());
719	    RadixPage* child = page->first_child;
720	    for (int i = 0; i < child->length; ++i) {
721	      (*page)[i + page->length] = (*child)[i];
722	    }
723	    page->length += child->length;
724	    page->first_child = child->first_child;
725	    for (RadixPage* p = child->first_child; p; p = p->next_sibling) {
726	      p->parent = page;
727	    }
728	    page->seq_ids = child->seq_ids;
729	    std::vector<int64_t> seq_ids = page->GetLocalSequence();
730	    for (int64_t id : seq_ids) seq2page[id] = page;
731	    child->seq_ids = nullptr;
732	    radix_page_pool->Free(child);
733	  }
734	
735	  /*!
736	   * \brief Split a radix tree page at given position, to accept new sequence.
737	   * e.g. SplitPage([1, 2, 3, 4, 5], 2) = [1, 2, _, _, _] -> [3, 4, 5, _, _].
738	   * \param page The radix tree page to split.
739	   * \param offset The position to split the radix tree page.
740	   * \return The splitted radix tree page. It can be different from the input radix tree page, as
741	   * there may be implicit radix tree page merge.
742	   */
743	  RadixPage* SplitPage(RadixPage* page, size_t offset) {
744	    TVM_FFI_ICHECK_LT(offset, page->length);
745	    RadixPage* child = radix_page_pool->Allocate();
746	    child->parent = page;
747	    child->first_child = page->first_child;
748	    for (RadixPage* p = page->first_child; p; p = p->next_sibling) {
749	      p->parent = child;
750	    }
751	    page->first_child = child;
752	    for (int i = offset; i < page->length; ++i) {
753	      (*child)[i - offset] = (*page)[i];
754	    }
755	    child->length = page->length - offset;
756	    page->length = offset;
757	    child->seq_ids = page->seq_ids;
758	    std::vector<int64_t> seq_ids = page->GetLocalSequence();
759	    for (int64_t id : seq_ids) seq2page[id] = child;
760	    page->seq_ids = nullptr;
761	    if (child->Mergeable()) {
762	      // The child page may be mergeable
763	      MergePage(child);
764	    }
765	    if (page->parent && page->parent->Mergeable()) {
766	      // The parent page may be mergeable
767	      page = page->parent;
768	      MergePage(page);
769	    }
770	    return page;
771	  }
772	
773	  /*!
774	   * \brief Match with given token from a radix tree page, stopping at first mismatch.
775	   * \param page The radix tree page to start matching.
776	   * \param tokens The given tokens to match.
777	   * \param length The length of given tokens.
778	   */
779	  std::tuple<RadixPage*, size_t, size_t> MatchSequence(RadixPage* page, const int32_t* tokens,
780	                                                       size_t length) {
781	    size_t offset = 0;
782	    while (offset < length) {
783	      if (RadixPage* child = page->FindChild(tokens[offset])) {
784	        // If child page starts with offset-th token, common prefix at least ends with child page
785	        size_t matched_offset = child->MatchPrefix(tokens + offset, length - offset);
786	        offset += matched_offset;
787	        if (matched_offset < child->length) {
788	          // Common prefix ends within child page
789	          return std::make_tuple(child, offset, matched_offset);
790	        }
791	        page = child;
792	      } else {
793	        // No child page starts with offset-th token, common prefix ends with current page
794	        return std::make_tuple(page, offset, page->length);
795	      }
796	    }
797	    return std::make_tuple(page, length, page->length);
798	  }
799	};
800	
801	PagedRadixTree PagedRadixTree::Create() {
802	  return PagedRadixTree(tvm::ffi::make_object<PagedRadixTreeImpl>());
803	}
804	
805	TVM_FFI_STATIC_INIT_BLOCK() {
806	  namespace refl = tvm::ffi::reflection;
807	  refl::GlobalDef()
808	      .def("mlc.serve.PagedRadixTree", []() { return PagedRadixTree::Create(); })
809	      .def("mlc.serve.PagedRadixTreeMatchPrefix",
810	           [](PagedRadixTree paged_radix_tree, Shape tokens) {
811	             std::vector<int32_t> token_ids{tokens.begin(), tokens.end()};
812	             auto [offset, seq_ids] = paged_radix_tree->MatchPrefix(token_ids);
813	             seq_ids.insert(seq_ids.begin(), offset);
814	             return Shape(seq_ids);
815	           })
816	      .def("mlc.serve.PagedRadixTreeExtendSequence",
817	           [](PagedRadixTree paged_radix_tree, int64_t seq_id, Shape tokens) {
818	             std::vector<int32_t> token_ids{tokens.begin(), tokens.end()};
819	             paged_radix_tree->ExtendSequence(seq_id, std::move(token_ids));
820	           })
821	      .def("mlc.serve.PagedRadixTreeRollBackSequence",
822	           [](PagedRadixTree paged_radix_tree, int64_t seq_id, int64_t num_tokens) {
823	             paged_radix_tree->RollBackSequence(seq_id, num_tokens);
824	           })
825	      .def("mlc.serve.PagedRadixTreeForkSequence",
826	           [](PagedRadixTree paged_radix_tree, int64_t seq_id, int64_t parent_seq_id,
827	              uint64_t forked_offset) {
828	             paged_radix_tree->ForkSequence(seq_id, parent_seq_id, forked_offset);
829	           })
830	      .def_method("mlc.serve.PagedRadixTreeHasSequence", &PagedRadixTreeObj::HasSequence)
831	      .def_method("mlc.serve.PagedRadixTreeAddSequence", &PagedRadixTreeObj::AddSequence)
832	      .def_method("mlc.serve.PagedRadixTreeRemoveSequence", &PagedRadixTreeObj::RemoveSequence)
833	      .def_method("mlc.serve.PagedRadixTreeGetSequence", &PagedRadixTreeObj::GetSequence)
834	      .def("mlc.serve.PagedRadixTreeGetSequenceLength",
835	           [](PagedRadixTree paged_radix_tree, int64_t seq_id) {
836	             return static_cast<int64_t>(paged_radix_tree->GetSequenceLength(seq_id));
837	           })
838	      .def("mlc.serve.PagedRadixTreeFreeCapacity", [](PagedRadixTree paged_radix_tree) {
