19	/*!
20	 * \brief The implementation of prefix cache.
21	 */
22	class PrefixCacheImpl : public PrefixCacheObj {
23	 public:
24	  /*!
25	   * \brief Constructor of paged radix tree.
26	   * \param max_num_recycling_seqs The maximum number of sequences in prefix cache.
27	   * \param remove_callback The optional callback function to call when removing a sequence.
28	   */
29	  explicit PrefixCacheImpl(size_t max_num_recycling_seqs, PrefixCacheRemoveCallback remove_callback)
30	      : radix_tree_(PagedRadixTree::Create()),
31	        max_num_recycling_seqs_(max_num_recycling_seqs),
32	        remove_callback_(std::move(remove_callback)) {
33	    recycling_seq_lrus_.clear();
34	    reversed_recycling_seq_lrus_.clear();
35	    seq_states_.clear();
36	    seq_sliding_window_infos_.clear();
37	    lru_counter_ = 0;
38	  }
39	
40	  /*!
41	   * \brief Insert a new tokenized sequence into Prefix Cache.
42	   * \param seq_id The sequence ID.
43	   * \param tokens The tokens of tokenized sequence.
44	   * \param sliding_window_size The sliding window size for the sequence, -1 as sliding window
45	   * disabled.
46	   * \param attention_sink_size The attention sink size for the sequence, 0 by default.
47	   * \return The matched result.
48	   */
49	  PrefixCacheMatchedResult InsertSequence(int64_t seq_id, std::vector<int32_t> tokens,
50	                                          int sliding_window_size, int attention_sink_size) final {
51	    TVM_FFI_ICHECK_NE(sliding_window_size, 0);
52	    TVM_FFI_ICHECK_GE(attention_sink_size, 0);
53	    TVM_FFI_ICHECK(seq_states_.find(seq_id) == seq_states_.end());
54	    TVM_FFI_ICHECK(seq_sliding_window_infos_.find(seq_id) == seq_sliding_window_infos_.end());
55	    TVM_FFI_ICHECK(!tokens.empty());
56	    CommitSequenceExtention();
57	    tokens.pop_back();
58	    auto [matched_offset, matched_seqs] = radix_tree_->MatchPrefix(tokens);
59	    std::pair<int, size_t> sliding_window_info{sliding_window_size, attention_sink_size};
60	    // No prefix matched, directly adding new sequence.
61	    if (!matched_offset) {
62	      radix_tree_->AddSequence(seq_id);
63	      seq_states_.emplace(seq_id, SequenceState::kActive);
64	      seq_sliding_window_infos_.emplace(seq_id, sliding_window_info);
65	      return PrefixCacheMatchedResult{0, -1, -1, 0};
66	    }
67	
68	    TVM_FFI_ICHECK(!matched_seqs.empty());
69	
70	    // The reusage of recycling sequences logic is different between with/without sliding window
71	    // enabled.
72	    if (sliding_window_size != -1) {
73	      // If sliding window enabled, the reusage of recycling sequences should be limited to exactly
74	      // matched. And no rolling back is allowed due to the sliding window.
75	      for (int64_t matched_seq_id : matched_seqs) {
76	        if (seq_states_.at(matched_seq_id) == SequenceState::kRecycling &&
77	            seq_sliding_window_infos_.at(matched_seq_id) == sliding_window_info) {
78	          size_t matched_seq_length = radix_tree_->GetSequenceLength(matched_seq_id);
79	          if (matched_seq_length == matched_offset) {
80	            ReuseRecyclingSequence(matched_seq_id);
81	            return PrefixCacheMatchedResult{matched_offset, -1, matched_seq_id, 0};
82	          }
83	        }
84	      }
85	    } else {
86	      // If sliding window is not enabled, we can greedily reuse the shortest recycling sequence
87	      // without sliding window, so that the loss or roll back of trailing tokens will be minimum.
88	      size_t shortest_recycling_seq_length = 0;
89	      int64_t shortest_recycling_seq_id = -1;
90	
91	      for (int64_t matched_seq_id : matched_seqs) {
92	        if (seq_states_.at(matched_seq_id) == SequenceState::kRecycling &&
93	            seq_sliding_window_infos_.at(matched_seq_id) == sliding_window_info) {
94	          size_t matched_seq_length = radix_tree_->GetSequenceLength(matched_seq_id);
95	          if (shortest_recycling_seq_id == -1 ||
96	              matched_seq_length < shortest_recycling_seq_length) {
97	            shortest_recycling_seq_id = matched_seq_id;
98	            shortest_recycling_seq_length = matched_seq_length;
99	          }
100	        }
101	      }
102	      if (shortest_recycling_seq_id != -1 && matched_offset > shortest_recycling_seq_length * 0.9) {
103	        ReuseRecyclingSequence(shortest_recycling_seq_id);
104	        if (shortest_recycling_seq_length > matched_offset) {
105	          // Recycling sequence is longer than new sequence, rolling back the redundant trailing
106	          // tokens, to match the new sequence.
107	          radix_tree_->RollBackSequence(shortest_recycling_seq_id,
108	                                        shortest_recycling_seq_length - matched_offset);
109	        }
110	        return PrefixCacheMatchedResult{matched_offset, -1, shortest_recycling_seq_id,
111	                                        shortest_recycling_seq_length - matched_offset};
112	      }
113	      // No reusage of recycling sequence, fallback to forking matched sequence. Currently, we only
114	      // fork from sequence without sliding window, due to current paged KVCache implementation.
115	      size_t longest_forking_offset = 0;
116	      int64_t longest_forking_seq_id = -1;
117	      for (int64_t matched_seq_id : matched_seqs) {
118	        auto [matched_seq_sliding_window_size, matched_seq_attention_sink_size] =
119	            seq_sliding_window_infos_.at(matched_seq_id);
120	        if (matched_seq_sliding_window_size != -1) {
121	          continue;
122	        }
123	        // If the matched is not enabled with sliding window, we can fork within matched offset
124	        // tokens arbitrarily.
125	        if (matched_offset > longest_forking_offset) {
126	          longest_forking_offset = matched_offset;
127	          longest_forking_seq_id = matched_seq_id;
128	        }
129	      }
130	      if (longest_forking_offset > 0) {
131	        radix_tree_->ForkSequence(seq_id, longest_forking_seq_id, longest_forking_offset);
132	        seq_states_.emplace(seq_id, SequenceState::kActive);
133	        seq_sliding_window_infos_.emplace(seq_id, sliding_window_info);
134	        return PrefixCacheMatchedResult{longest_forking_offset, longest_forking_seq_id, -1, 0};
135	      }
136	    }
137	    // No forking from matched sequence, fallback to adding new sequence.
138	    radix_tree_->AddSequence(seq_id);
139	    seq_states_.emplace(seq_id, SequenceState::kActive);
140	    seq_sliding_window_infos_.emplace(seq_id, sliding_window_info);
141	    return PrefixCacheMatchedResult{0, -1, -1, 0};
142	  }
143	
144	  /*!
145	   * \brief Extend a sequence with new tokenized sequence suffix.
146	   * \param seq_id The sequence to be extended.
147	   * \param tokens The tokens of tokenized sequence suffix to extend.
148	   * \throw Error if the given sequence id is not valid or active.
149	   */
150	  void ExtendSequence(int64_t seq_id, const std::vector<int32_t>& tokens) final {
151	    uncommitted_extended_token_ids_.emplace_back(seq_id, tokens);
152	  }
153	
154	  void CommitSequenceExtention() final {
155	    if (uncommitted_extended_token_ids_.empty()) {
156	      return;
157	    }
158	    NVTXScopedRange nvtx_scope("PrefixCache commit sequence extension");
159	    for (const auto& [seq_id, uncommitted_token_ids] : uncommitted_extended_token_ids_) {
160	      if (!HasSequence(seq_id)) {
161	        // The sequence has been removed. Hence no action is needed.
162	        continue;
163	      }
164	      const auto& it = seq_states_.find(seq_id);
165	      TVM_FFI_ICHECK(it == seq_states_.end() || it->second == SequenceState::kActive);
166	      radix_tree_->ExtendSequence(seq_id, uncommitted_token_ids);
167	    }
168	    uncommitted_extended_token_ids_.clear();
169	  }
170	
171	  /*!
172	   * \brief Roll back a sequence by number of tokens.
173	   * \param seq_id The sequence ID for index.
174	   * \param num_tokens The number of tokens to be rolled back.
175	   * \throw Error if the given sequence id is not valid or active.
176	   */
177	  void RollBackSequence(int64_t seq_id, size_t num_tokens) final {
178	    CommitSequenceExtention();
179	    TVM_FFI_ICHECK(seq_states_.at(seq_id) == SequenceState::kActive);
180	    radix_tree_->RollBackSequence(seq_id, num_tokens);
181	  }
182	
183	  /*!
184	   * \brief Recycle a sequence. The recycled sequence will not be removed immediately, as long as
185	   * memory is sufficient and the number of sequence in prefix cache belows the maximum number of
186	   * sequence. And it will be reused again in the future request.
187	   * \param seq_id The sequence to be recycled.
188	   * \param lazy The flag if the sequence should be removed lazily or intermediary.
189	   * \throw Error if the given sequence id is not valid.
190	   */
191	  void RecycleSequence(int64_t seq_id, bool lazy = true) final {
192	    CommitSequenceExtention();
193	    TVM_FFI_ICHECK(seq_states_.at(seq_id) == SequenceState::kActive);
194	    TVM_FFI_ICHECK(recycling_seq_lrus_.find(seq_id) == recycling_seq_lrus_.end());
195	    if (lazy && max_num_recycling_seqs_ != 0) {
196	      // Remove the sequence lazily.
197	      if (recycling_seq_lrus_.size() == max_num_recycling_seqs_) {
198	        // If prefix cache has reached maximum number of recycling sequences, try to pop one
199	        // recycling sequence.
200	        TVM_FFI_ICHECK(TryFreeMemory());
201	        TVM_FFI_ICHECK_EQ(recycling_seq_lrus_.size(), max_num_recycling_seqs_ - 1);
202	      }
203	      seq_states_.at(seq_id) = SequenceState::kRecycling;
204	      ++lru_counter_;
205	      recycling_seq_lrus_.emplace(seq_id, lru_counter_);
206	      reversed_recycling_seq_lrus_.emplace(lru_counter_, seq_id);
207	    } else {
208	      // Remove the sequence intermediately.
209	      radix_tree_->RemoveSequence(seq_id);
210	      if (remove_callback_ != nullptr) {
211	        remove_callback_(seq_id);
212	      }
213	      TVM_FFI_ICHECK(seq_states_.erase(seq_id));
214	      TVM_FFI_ICHECK(seq_sliding_window_infos_.erase(seq_id));
215	    }
216	  }
217	
218	  /*!
219	   * \brief Try to remove recycling sequence to free up memory. It will remove the oldest recycling
220	   sequence.
221	   * \return The flag if there is a sequence removed. In other word, return true when memory is
222	   freed successfully.
223	   * \throw Error if the given sequence id is not valid.
224	   */
225	  bool TryFreeMemory() final {
226	    NVTXScopedRange nvtx_scope("PrefixCache TryFreeMemory");
227	    if (reversed_recycling_seq_lrus_.empty()) {
228	      // There is no recycling sequence. No memory can be freed.
229	      return false;
230	    }
231	    auto [lru, seq_id] = *reversed_recycling_seq_lrus_.begin();
232	    TVM_FFI_ICHECK(seq_states_.at(seq_id) == SequenceState::kRecycling);
233	    TVM_FFI_ICHECK_EQ(recycling_seq_lrus_.at(seq_id), lru);
234	    radix_tree_->RemoveSequence(seq_id);
235	    if (remove_callback_ != nullptr) {
236	      remove_callback_(seq_id);
237	    }
238	    TVM_FFI_ICHECK(seq_states_.erase(seq_id));
239	    TVM_FFI_ICHECK(recycling_seq_lrus_.erase(seq_id));
240	    TVM_FFI_ICHECK(reversed_recycling_seq_lrus_.erase(lru));
241	    TVM_FFI_ICHECK(seq_sliding_window_infos_.erase(seq_id));
242	    return true;
243	  }
244	
245	  /*!
246	   * \brief Check if a sequence exists.
247	   * \param seq_id The sequence ID for index.
248	   * \return The sequence existence.
249	   * \throw Error if sequence ID is not valid.
250	   */
251	  bool HasSequence(int64_t seq_id) final { return radix_tree_->HasSequence(seq_id); }
252	
253	  /*!
254	   * \brief Reset the prefix cache to initial status.
255	   */
256	  void Reset() final {
257	    radix_tree_->Reset();
258	    recycling_seq_lrus_.clear();
259	    reversed_recycling_seq_lrus_.clear();
260	    seq_states_.clear();
261	    seq_sliding_window_infos_.clear();
262	    uncommitted_extended_token_ids_.clear();
263	    lru_counter_ = 0;
264	  }
265	
266	  PrefixCacheMode Mode() final { return PrefixCacheMode::kRadix; }
267	
268	 private:
269	  void ReuseRecyclingSequence(int64_t seq_id) {
270	    TVM_FFI_ICHECK(seq_states_.at(seq_id) == SequenceState::kRecycling);
271	    size_t lru = recycling_seq_lrus_.at(seq_id);
272	    TVM_FFI_ICHECK_EQ(reversed_recycling_seq_lrus_.at(lru), seq_id);
273	    seq_states_.at(seq_id) = SequenceState::kActive;
274	    TVM_FFI_ICHECK(recycling_seq_lrus_.erase(seq_id));
275	    TVM_FFI_ICHECK(reversed_recycling_seq_lrus_.erase(lru));
276	  }
277	
278	  /*!
279	   * \brief The sequence states.
280	   */
281	  enum class SequenceState : int {
282	    /*!
283	     * \brief The state of active sequence. In this state, the sequence can be forked only. When
284	     * recycling a sequence, it will transfer to kRecycling.
285	     */
286	    kActive = 0,
287	    /*!
288	     * \brief The state of recycling sequence. In this state, the sequence can be forked or be
289	     * reused. And it will transfer to kActive only when reused.
290	     */
291	    kRecycling = 1,
292	  };
293	  /*!
294	   * \brief The core data structure radix tree.
295	   */
296	  PagedRadixTree radix_tree_;
297	  /*!
298	   * \brief The map from sequence to LRU time stamps.
299	   */
300	  std::unordered_map<int64_t, size_t> recycling_seq_lrus_;
301	  /*!
302	   * \brief The map from LRU time stamps to sequence, used to find the sequence with earliest LRU
303	   * time stamp.
304	   */
305	  std::unordered_map<size_t, int64_t> reversed_recycling_seq_lrus_;
306	  /*!
307	   * \brief The maximum number of recycling sequences in prefix cache. Set -1 as infinite prefix
308	   * cache.
309	   */
310	  int max_num_recycling_seqs_ = -1;
311	  /*!
312	   * \brief The LRU counter.
313	   */
314	  size_t lru_counter_ = 0;
315	  /*!
316	   * \brief The callback function to call when removing a sequence. This can be used to
317	   * removing sequence in KVCache and return sequence ID to ID manager lazily
318	   */
319	  PrefixCacheRemoveCallback remove_callback_ = nullptr;
320	  /*!
321	   * \brief The map from sequence to its sequence states.
322	   */
323	  std::unordered_map<int64_t, SequenceState> seq_states_;
324	  /*!
325	   * \brief The map from sequence to its sliding window information. The sliding window information
326	   * is a pair of sliding window size and attention sink size. The sliding window size is -1 for
327	   * sliding window disabled, or positive for sliding window size. The attention sink size is
328	   * non-negative and used when sliding window size is positive.
329	   */
330	  std::unordered_map<int64_t, std::pair<int, size_t>> seq_sliding_window_infos_;
331	  /*!
332	   * \brief The collection of uncommitted extended token ids of sequences.
333	   * The "ExtendSequence" method only lazily add token ids into this collection,
334	   * and these uncommitted token ids will be committed when needed.
335	   *
336	   * Note: Since the tokens stored are references, CommitSequenceExtention should be called after
337	   * each action, to avoid the uncaught changes of uncomitted extended token ids.
338	   */
339	  std::vector<std::pair<int64_t, const std::vector<int32_t>&>> uncommitted_extended_token_ids_;
340	};  // namespace serve
341	
342	/*!
343	 * \brief The implementation of no prefix cache.
344	 */
345	class NoPrefixCache : public PrefixCacheObj {
346	 public:
347	  /*!
348	   * \brief Insert a new tokenized sequence into Prefix Cache.
349	   * \param seq_id The sequence ID.
350	   * \param tokens The tokens of tokenized sequence.
351	   * \param sliding_window_size The sliding window size for the sequence, -1 as sliding window
352	   * disabled.
353	   * \param attention_sink_size The attention sink size for the sequence, 0 by default.
354	   * \return The matched result.
355	   */
356	  PrefixCacheMatchedResult InsertSequence(int64_t seq_id, std::vector<int32_t> tokens,
357	                                          int sliding_window_size, int attention_sink_size) final {
358	    // Since there is no prefix cache, always return as new sequence.
359	    return PrefixCacheMatchedResult{0, -1, -1, 0};
360	  }
361	
362	  /*!
363	   * \brief Extend a sequence with new tokenized sequence suffix.
364	   * \param seq_id The sequence to be extended.
365	   * \param tokens The tokens of tokenized sequence suffix to extend.
366	   * \throw Error if called since this should never be called.
367	   */
368	  void ExtendSequence(int64_t seq_id, const std::vector<int32_t>& tokens) final {
369	    // No-op;
370	  }
371	
372	  void CommitSequenceExtention() final {
373	    // No-op;
374	  }
375	
376	  /*!
377	   * \brief Roll back a sequence by number of tokens.
378	   * \param seq_id The sequence ID for index.
379	   * \param num_tokens The number of tokens to be rolled back.
380	   * \throw Error if called since this should never be called.
381	   */
382	  void RollBackSequence(int64_t seq_id, size_t num_tokens) final {
383	    // Since there is no prefix cache, this method should never be called.
384	    LOG(FATAL) << "Unreachable code.";
385	  }
386	
387	  /*!
388	   * \brief Recycle a sequence. The recycled sequence will not be removed immediately, as long as
389	   * memory is sufficient and the number of sequence in prefix cache belows the maximum number of
390	   * sequence. And it will be reused again in the future request.
391	   * \param seq_id The sequence to be recycled.
392	   * \param lazy The flag if the sequence should be removed lazily or intermediary.
393	   * \throw Error if the given sequence id is not valid.
394	   */
395	  void RecycleSequence(int64_t seq_id, bool lazy = true) final {
396	    // Since there is no prefix cache, this method should never be called.
397	    LOG(FATAL) << "Unreachable code.";
398	  }
399	
400	  /*!
401	   * \brief Try to remove recycling sequence to free up memory. It will remove the oldest
402	   recycling sequence.
403	   * \return Always return false as no sequence stored.
